form:Form.form:Scripts:
		function PosOnLoad()
{
	if (Ctrl('main').GetMode()=='NEW')
  {
  	Ctrl('oi_empresa').SetXValue('');
  }

	if (Ctrl('main').GetMode()=='SHOW' || Ctrl('main').GetMode()=='EDIT')
  {
    var nSQL = GetProxy().SQLService();
	  var xmlParam = new NomadXML('PARAM');
	  xmlParam.SetAttr('oi_personal_emp', Ctrl('oi_personal_emp').GetXValue());	  
		var objResult = nSQL.GetOBJ(Ctrl("main").getResource('QRY_EMPRESA'), xmlParam.ToString());		
		Ctrl('oi_empresa').SetXValue(objResult.oi_empresa);
  }	
}

qry:select.qry:xquery:
for $r in SQL('
SELECT PER02_PERSONAL_EMP.oi_empresa FROM PER02_PERSONAL_EMP WHERE PER02_PERSONAL_EMP.oi_personal_emp = {$PARAM/@oi_personal_emp}
')/ROWS/ROW
